import type {
  MarketListResponse,
  MarketDetailResponse,
  MarketPreviewResponse,
  MarketEventsResponse,
  MarketCommentsResponse,
  EngineStatsResponse,
  MarketAnalyticsResponse,
  AccountRiskResponse,
  AccountPnlResponse,
  OrderResponse,
  CommentResponse,
  ApiError,
  AnalyticsInterval,
  CommentPayload,
  ProbabilityEditPayload,
  EventTradePayload,
  Session,
  MarketListFilters,
} from "./types";
import { normalizeMarketListFilters } from "@/lib/marketListFilters";

const API_BASE = import.meta.env.VITE_API_BASE ?? "";

export class BayesApiError extends Error {
  constructor(
    public status: number,
    public code: string,
    public details: Record<string, unknown> = {},
  ) {
    super(`${code}: ${status}`);
    this.name = "BayesApiError";
  }
}

async function request<T>(
  path: string,
  options: RequestInit = {},
  session?: Session,
): Promise<T> {
  const headers: Record<string, string> = {
    ...(options.headers as Record<string, string>),
  };

  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
    headers["Content-Type"] = "application/json";
  }

  if (session?.agentId) {
    headers["X-Bayes-Agent-Id"] = session.agentId;
  }

  const res = await fetch(`${API_BASE}${path}`, {
    ...options,
    headers,
  });

  const body = await res.json();

  if (!res.ok) {
    const err = body as ApiError;
    throw new BayesApiError(
      res.status,
      err.error?.code ?? "unknown_error",
      err.error?.details ?? {},
    );
  }

  return body as T;
}

export function listMarkets(
  filters: MarketListFilters = {},
): Promise<MarketListResponse> {
  const normalized = normalizeMarketListFilters(filters);
  const params = new URLSearchParams();

  if (normalized.status) {
    params.set("status", normalized.status);
  }

  if (normalized.sort) {
    params.set("sort", normalized.sort);
  }

  if (normalized.q) {
    params.set("q", normalized.q);
  }

  const qs = params.toString();
  return request<MarketListResponse>(`/v1/markets${qs ? `?${qs}` : ""}`);
}

export interface CreateMarketPayload {
  title: string;
  description: string;
  outcomes: Array<{ id: string; name: string }>;
  expires_at: string;
  liquidity?: number;
}

